class AppDelegate: NSObject, UIApplicationDelegate {
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        PromoLinkHandler.shared.handleURL(url)
        return true
    }
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey : Any]? = nil) -> Bool {
        return true
    }
}

struct PromoCode: Codable, Equatable {
    let code: String
    let discount: Int
    let appliedDate: Date
}

class UserAccountManager: ObservableObject {
    static let shared = UserAccountManager()
    
    @Published var currentPromoCode: PromoCode?
    @Published var promoHistory: [PromoCode] = []
    
    private let userDefaults = UserDefaults.standard
    private let promoCodeKey = "currentPromoCode"
    private let promoHistoryKey = "promoHistory"
    
    private init() {
        loadPromoData()
    }
    
    func applyPromoCode(_ code: String, discount: Int) -> Bool {
        guard discount > 0 && discount <= 100 else { return false }
        guard !code.isEmpty else { return false }
        
        let newPromo = PromoCode(code: code, discount: discount, appliedDate: Date())
        
        DispatchQueue.main.async {
            self.currentPromoCode = newPromo
            self.promoHistory.insert(newPromo, at: 0)
            if self.promoHistory.count > 10 {
                self.promoHistory = Array(self.promoHistory.prefix(10))
            }
            self.savePromoData()
        }
        
        return true
    }
    
    func clearCurrentPromo() {
        DispatchQueue.main.async {
            self.currentPromoCode = nil
            self.savePromoData()
        }
    }
    
    private func savePromoData() {
        if let promoCode = currentPromoCode,
           let encoded = try? JSONEncoder().encode(promoCode) {
            userDefaults.set(encoded, forKey: promoCodeKey)
        } else {
            userDefaults.removeObject(forKey: promoCodeKey)
        }
        
        if let encoded = try? JSONEncoder().encode(promoHistory) {
            userDefaults.set(encoded, forKey: promoHistoryKey)
        }
    }
    
    private func loadPromoData() {
        if let data = userDefaults.data(forKey: promoCodeKey),
           let promoCode = try? JSONDecoder().decode(PromoCode.self, from: data) {
            currentPromoCode = promoCode
        }
        
        if let data = userDefaults.data(forKey: promoHistoryKey),
           let history = try? JSONDecoder().decode([PromoCode].self, from: data) {
            promoHistory = history
        }
    }
}

class PromoLinkHandler: ObservableObject {
    static let shared = PromoLinkHandler()
    
    @Published var lastProcessedURL: URL?
    @Published var lastError: String?
    @Published var showSuccessAlert = false
    @Published var successMessage = ""
    
    private let validHost = "myapp.com"
    private let validPath = "/promo"
    
    private init() {}
    
    func handleURL(_ url: URL) {
        lastProcessedURL = url
        lastError = nil
        
        guard url.host == validHost else {
            lastError = "Invalid URL host"
            return
        }
        
        guard url.path == validPath else {
            lastError = "Invalid URL path"
            return
        }
        
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let queryItems = components.queryItems else {
            lastError = "No query parameters found"
            return
        }
        
        var promoCode: String?
        var discount: Int?
        
        for item in queryItems {
            switch item.name {
            case "code":
                promoCode = item.value
            case "discount":
                if let value = item.value {
                    discount = Int(value)
                }
            default:
                break
            }
        }
        
        guard let code = promoCode, !code.isEmpty else {
            lastError = "Missing or invalid promo code"
            return
        }
        
        guard let discountValue = discount, discountValue > 0, discountValue <= 100 else {
            lastError = "Missing or invalid discount percentage"
            return
        }
        
        if UserAccountManager.shared.applyPromoCode(code, discount: discountValue) {
            DispatchQueue.main.async {
                self.successMessage = "Promo code '\(code)' applied! You get \(discountValue)% off"
                self.showSuccessAlert = true
            }
        } else {
            lastError = "Failed to apply promo code"
        }
    }
}

